        long long new_dp0 = 0, new_dp1 = 0;
        long long new_dp00 = 0, new_dp11 = 0;

        if (parity == 0) {
            // Current element is even
            new_dp0 = (1 + dp0 + dp1) % MOD; // can add to any previous subsequence or start new
            new_dp00 = dp0 % MOD; // can add to sequences ending with one even
            // dp11 remains 0 since we can't have two odds followed by even
        } else {
            // Current element is odd
            new_dp1 = (1 + dp0 + dp1) % MOD; // can add to any previous subsequence or start new
            new_dp11 = dp1 % MOD; // can add to sequences ending with one odd
            // dp00 remains 0 since we can't have two evens followed by odd
        }

        // Update total: add all new stable subsequences ending at i
        total = (total + new_dp0 + new_dp1 - new_dp00 - new_dp11) % MOD;
        if (total < 0) total += MOD;

        // Update dp states for next iteration
        dp0 = new_dp0;
        dp1 = new_dp1;
        dp00 = new_dp00;
        dp11 = new_dp11;
    }

    return total % MOD;
}
