    // where j is the parity of the last element (0: even, 1: odd),
    // and k is the number of consecutive elements with the same parity (1 or 2)
    long long dp[n][2][2];
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 2; ++j) {
            for (int k = 0; k < 2; ++k) {
                dp[i][j][k] = 0;
            }
        }
    }

    // Initialize for the first element
    int parity = nums[0] % 2;
    dp[0][parity][0] = 1;

    long long total = 1; // starts with the first element

    for (int i = 1; i < n; ++i) {
        int current_parity = nums[i] % 2;

        // The current element as a new subsequence
        dp[i][current_parity][0] = 1;

        // Add to total
        total = (total + 1) % MOD;

        // Iterate through all previous elements
        for (int j = 0; j < i; ++j) {
            for (int p = 0; p < 2; ++p) {
                for (int k = 0; k < 2; ++k) {
                    if (dp[j][p][k] == 0) continue;

                    if (p == current_parity) {
                        if (k == 0) {
                            // Can add to make k+1 = 1
                            dp[i][p][k + 1] = (dp[i][p][k + 1] + dp[j][p][k]) % MOD;
                            total = (total + dp[j][p][k]) % MOD;
                        }
                        // else k == 1, adding would make k+1 = 2, which is allowed
                        // but adding another would make it 3, which is not allowed
                    } else {
                        // Different parity, reset the consecutive count
                        dp[i][current_parity][0] = (dp[i][current_parity][0] + dp[j][p][k]) % MOD;
                        total = (total + dp[j][p][k]) % MOD;
                    }
                }
            }
        }
    }

    return total;
}
