const int MOD = 1e9 + 7;

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n == 0) return 0;

    // dp[i][j] represents the number of stable subsequences ending at i, with j consecutive elements of same parity
    // j can be 1 or 2 (since j >=3 is invalid)
    vector<vector<long long>> dp(n, vector<long long>(3, 0));

    // Initialize: each single element is a valid subsequence
    for (int i = 0; i < n; ++i) {
        dp[i][1] = 1;
    }

    long long total = 0;
    total += n; // all single elements

    for (int i = 1; i < n; ++i) {
        for (int j = 0; j < i; ++j) {
            if ((nums[i] % 2) == (nums[j] % 2)) {
                // Same parity as previous
                dp[i][2] = (dp[i][2] + dp[j][1]) % MOD;
                // No need to add dp[j][2] because it would lead to 3 consecutive same parity
            } else {
                // Different parity
                dp[i][1] = (dp[i][1] + dp[j][1] + dp[j][2]) % MOD;
            }
        }
        total = (total + dp[i][1] + dp[i][2]) % MOD;
    }

    return total;
}
